class CoapServer:
    TYPE_CON = 0
    TYPE_NON = 1
    TYPE_ACK = 2
    TYPE_RST = 3
    
    CODE_GET = 1
    CODE_POST = 2
    CODE_PUT = 3
    CODE_DELETE = 4
    
    CODE_CREATED = 65
    CODE_DELETED = 66
    CODE_VALID = 67
    CODE_CHANGED = 68
    CODE_CONTENT = 69
    CODE_BAD_REQUEST = 128
    CODE_NOT_FOUND = 132
    CODE_METHOD_NOT_ALLOWED = 133
